// Parse Telegram message forwarded via the Maestro webhook
// Updated 2026-05-09: support THDD group + bot-to-bot @-mentions (path C smoke).
const ALLOWED_CHAT_IDS = ['6091970994', '-5276079329']; // Tyler DM, THDD group
const ALLOWED_SENDERS = [6091970994, 8767113351]; // Tyler, Aether_MapMaker_bot

const body = $input.first().json.body || $input.first().json;
const message = body.message || body;
const text = (message.text || '').trim();

// Strict chat_id extraction. NO fallback — a missing chat_id is a refusal,
// not an implicit "trust Tyler". Removes a sub-bug from the prior version.
const raw_chat_id = message.chat?.id ?? body.chat_id;
if (raw_chat_id == null) {
  throw new Error('No chat_id in payload — refusing to process');
}
const chat_id = String(raw_chat_id);

// Tier 0 allowlist gate (OPS-023). Combined with the X-Telegram-Bot-Api-
// Secret-Token enforcement on the webhook node (OPS-022), the only path
// to this code is "Telegram-genuine + chat in allowlist".
if (!ALLOWED_CHAT_IDS.includes(chat_id)) {
  throw new Error('Unauthorized chat_id: ' + chat_id);
}

// Group-context sender gate (added 2026-05-09 for path-C smoke). In private
// DMs chat_id == user_id so the chat allowlist is sufficient. In groups
// (negative chat_id), additionally verify the sender is in {Tyler, Mapmaker}
// so random group members can't /build.
const sender_id = message.from?.id;
if (chat_id.startsWith('-') && !ALLOWED_SENDERS.includes(sender_id)) {
  throw new Error('Unauthorized sender in group chat: ' + sender_id);
}

if (!text.startsWith('/')) return [{ json: { cmd: 'unknown', args: [], chat_id, text } }];

const parts = text.split(/\s+/);
// Strip @bot mention so /build@Mastro_ClaudeBot matches /build downstream
// (added 2026-05-09 — pre-fix the Switch node's strict equals failed on @-mentions).
const cmd = parts[0].toLowerCase().replace(/@\w+$/, '');
const args = parts.slice(1);

// the-bridge C4 (2026-05-06): expose arg1 + clue (numeric, strips 'clue-' prefix)
// so /build <hunt> clue-<n> can dispatch to hunter-exec.py with --clue <int>.
const arg1 = args[1] || '';
const clue = (arg1.replace(/^clue-/i, '') || '1');  // default to clue 1 when omitted (the-undertaker C3 fix 2026-05-10)

return [{ json: { cmd, args, arg0: args[0] || '', arg1, clue, chat_id, user_id: sender_id, username: message.from?.username, text } }];

// Build reply text from previous node output
const prev = $input.first().json;
const stdout = prev.stdout || prev.sessions_started || JSON.stringify(prev);
const cmd = $('Parse Command').first().json.cmd || '';
const arg0 = $('Parse Command').first().json.arg0 || '';
const arg1 = $('Parse Command').first().json.arg1 || '';

let reply;
switch (cmd) {
  case '/build':
    reply = `\u{1F309} Building ${arg0}${arg1 ? ' ' + arg1 : ''}\u2026 hunter-exec firing \u2014 proof.txt + COMPLETE.md committing as Hunter, ETA <2 min.`;
    break;
  case '/status':
    reply = `\u{1F4CA} ${arg0} status:\n${stdout.trim().slice(0, 600)}`;
    break;
  case '/kill':
    reply = `\u{1F6D1} Killed session: ${arg0}`;
    break;
  case '/babysit':
    reply = `\u{1F476} Babysitter started for: ${arg0}`;
    break;
  case '/hunts':
    reply = `\u{1F5C2} Active contexts:\n${stdout.trim()}`;
    break;
  case '/quests':
    reply = ($input.first().json.markdown) || (prev.markdown) || (prev.body && prev.body.markdown) || '_no markdown returned_';
    break;
  default:
    if (cmd === '/start' || cmd === '/help') {
      reply = `\u{1F3BC} Maestro online.\n\n` +
              `Commands:\n` +
              `/build <hunt> \u2014 start a hunt\n` +
              `/status <hunt> \u2014 check status\n` +
              `/kill <session> \u2014 stop a session\n` +
              `/babysit <session> \u2014 restart babysitter\n` +
              `/hunts \u2014 list active contexts`;
    } else if (cmd === 'unknown') {
      reply = `\u{1F3BC} Maestro listening. Send a command:\n` +
              `/build /status /kill /babysit /hunts\n` +
              `(or /help for details)`;
    } else {
      reply = `\u2753 Unknown command: ${cmd}\n` +
              `Try /help for the full list.`;
    }
}

return [{ json: { reply, chat_id: $('Parse Command').first().json.chat_id } }];

// Parse Quartermaster preflight stdout
// Shell Bridge response shape: { stdout: "...", stderr: "...", exit_code: N }
// QM stdout is the JSON-encoded result object.
const prev = $input.first().json;
const parse = $('Parse Command').first().json;

let qm = null;
let qm_parse_error = null;
const raw = (prev.stdout || prev.body?.stdout || '').trim();
try {
  qm = raw ? JSON.parse(raw) : null;
} catch (e) {
  qm_parse_error = String(e).slice(0, 200);
}

// Fail-safe: if QM didn't run cleanly, treat as NOT ready with a synthetic gap.
// Substrate-honesty: don't silently let dispatch proceed when the gate itself failed.
if (qm == null) {
  qm = {
    version: 'quartermaster-v1.1',
    hunt: parse.arg0,
    clue: parse.clue,
    ready: false,
    gaps: [{
      type: 'preflight_gate_unreachable',
      severity: 'block',
      error: qm_parse_error || 'empty stdout from Shell Bridge',
      raw_preview: raw.slice(0, 200)
    }],
    blocking_gap_count: 1,
    warn_gap_count: 0,
  };
}

return [{
  json: {
    qm,
    qm_ready: qm.ready === true,
    cmd: parse.cmd,
    arg0: parse.arg0,
    arg1: parse.arg1,
    clue: parse.clue,
    chat_id: parse.chat_id,
    args: parse.args,
    text: parse.text,
  }
}];

// Format Quartermaster abort reply
// Fires when qm.ready === false. Builds a tightly-scoped Telegram reply
// listing blocking gaps so Tyler can fix them before re-firing /build.
const j = $input.first().json;
const qm = j.qm || {};
const gaps = qm.gaps || [];
const blocking = gaps.filter(g => g.severity === 'block');
const warns = gaps.filter(g => g.severity === 'warn');

const lines = [];
lines.push(`🚫 Quartermaster blocks /build ${j.arg0 || '?'} clue-${j.clue || '?'}`);
lines.push(`Source: ${qm.prompt_source || '(PROMPT not found)'}`);
lines.push(`Blocking: ${blocking.length} · Warnings: ${warns.length}`);
lines.push('');
lines.push('Blocking gaps:');
if (blocking.length === 0) {
  lines.push('  (none — but ready=false, possible gate bug)');
} else {
  for (const g of blocking.slice(0, 8)) {
    const detail = g.path || g.repo || g.error || g.status || '';
    lines.push(`  • ${g.type}${detail ? ' — ' + String(detail).slice(0, 120) : ''}`);
  }
  if (blocking.length > 8) lines.push(`  …and ${blocking.length - 8} more`);
}
if (warns.length) {
  lines.push('');
  lines.push(`Warnings (non-blocking): ${warns.map(w => w.type).join(', ').slice(0, 200)}`);
}
lines.push('');
lines.push('Fix the blocking gaps and re-fire /build.');

return [{
  json: {
    reply: lines.join('\n'),
    chat_id: j.chat_id,
  }
}];

// C4 voyage command handler
// brain-write /api/brain/read is absent — using GitHub raw fallback
const parsed = $('Parse Command').first().json;
const chat_id = parsed.chat_id;
const hunt_slug = (parsed.args || [])[0] || '';

if (!hunt_slug) {
  return [{ json: { reply: 'Usage: /voyage <hunt-slug>', chat_id } }];
}

const charterUrl =
  `https://raw.githubusercontent.com/AetherCreator/SuperClaude/main/hunts/${hunt_slug}/CHARTER.md`;

let charterText;
try {
  const charterResp = await fetch(charterUrl);
  if (!charterResp.ok) {
    const reply = `❌ No charter at hunts/${hunt_slug}/CHARTER.md (HTTP ${charterResp.status})`;
    return [{ json: { reply, chat_id } }];
  }
  charterText = await charterResp.text();
} catch (e) {
  return [{ json: { reply: `❌ Charter fetch error: ${e.message}`, chat_id } }];
}

// Extract §1 Treasure section
const m = charterText.match(/##\s*1\.\s*The Treasure[^\n]*\n([\s\S]*?)(?=\n##\s*2\.|$)/m);
const hunt_intent = (m ? m[1].trim() : charterText.trim()).slice(0, 4000);

// POST to voyage worker
const now = new Date();
const expectedBy = new Date(now.getTime() + 86400000).toISOString();
const voyageWorkerUrl = $env.VOYAGE_WORKER_BASE_URL || 'https://voyage.tveg-baking.workers.dev';

let voyageResult;
try {
  const voyageResp = await fetch(`${voyageWorkerUrl}/voyage/start`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      hunt: hunt_slug,
      hunt_intent,
      scope_constraints: 'via /voyage Telegram command',
      expected_completion_by: expectedBy,
    }),
  });
  if (!voyageResp.ok) {
    const errBody = await voyageResp.text();
    const reply = `❌ Voyage start failed (HTTP ${voyageResp.status}): ${errBody.slice(0, 200)}`;
    return [{ json: { reply, chat_id } }];
  }
  voyageResult = await voyageResp.json();
} catch (e) {
  return [{ json: { reply: `❌ Voyage POST error: ${e.message}`, chat_id } }];
}

const voyage_id = voyageResult.voyage_id;
const reply = [
  '🚀 Voyage started',
  `• id: ${voyage_id}`,
  `• hunt: ${hunt_slug}`,
  `• role: captain`,
  `• state: ${voyageWorkerUrl}/voyage/${voyage_id}`,
].join('\n').slice(0, 4096);

return [{ json: { reply, chat_id } }];
